import { useState, useMemo } from 'react';
import type { Props, HookReturn, Element } from '/virtual/types';

export const usePeriodicTable = ({ elements }: Props): HookReturn => {
  const { elements } = props;

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const lowerQuery = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerQuery) ||
        el.symbol.toLowerCase().includes(lowerQuery)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    return Array.from(new Set(elements.map((el) => el.category)));
  }, [elements]);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
  };
};

