import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function ElementCell(props: ElementCellProps) {
  const { element, isSelected, onClick } = props;

  const getCategoryColor = (category: string) => {
    // Simplified category color map using theme tokens
    if (category.includes('metal')) return 'var(--ggui-color-primary-100)';
    if (category.includes('gas')) return 'var(--ggui-color-info-100)';
    return 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <button
      type="button"
      onClick={onClick}
      style={{
        background: getCategoryColor(element.category),
        borderRadius: 'var(--ggui-shape-radius-md)',
        padding: 'var(--ggui-spacing-2)',
        gridColumn: element.col,
        gridRow: element.row,
        border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
        cursor: 'pointer',
        transition: 'all 200ms var(--ggui-easing-easeOut)',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{element.atomicNumber}</Text>
      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">{element.symbol}</Text>
    </button>
  );
}


