import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}

export function useComponent(props: Props): HookReturn {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;

  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<ProfileData>(() => ({
    name: '',
    email: '',
    avatar: avatarOptions[0] || '',
    role: roleOptions[0] || '',
    emailNotifications: true,
    theme: 'light',
    ...initialProfile,
  }));

  const isStepValid = useMemo(() => {
    if (currentStep === 0) {
      const emailRegex = /^\S+@\S+\.\S+$/;
      return !!(formData.name && formData.email && emailRegex.test(formData.email));
    }
    return true;
  }, [currentStep, formData]);

  const isNextDisabled = !isStepValid || currentStep === 2;

  const handleNext = useCallback(() => {
    if (currentStep < 2) setCurrentStep((prev) => prev + 1);
  }, [currentStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 0) setCurrentStep((prev) => prev - 1);
  }, [currentStep]);

  const updateField = useCallback(<K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  }, []);

  const completeSetup = useCallback(() => {
    onComplete(formData);
  }, [formData, onComplete]);

  return {
    currentStep,
    formData,
    isNextDisabled,
    handleNext,
    handleBack,
    updateField,
    completeSetup,
  };
}


